import React from 'react';

// Sidebar navigation for admin dashboard
// Calls onNavigate with section name
export default function AdminSidebar({ onNavigate, active }) {
  return (
    <aside className="h-screen w-56 bg-white border-r border-gray-200 flex flex-col py-8 px-4 shadow-md">
      <h2 className="text-xl font-bold mb-8 text-green-600 text-center">Admin Panel</h2>
      <nav className="flex flex-col gap-4">
        <button onClick={() => onNavigate('dashboard')} className={`text-left px-4 py-2 rounded font-medium transition ${active === 'dashboard' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}>Dashboard</button>
        <button onClick={() => onNavigate('user')} className={`text-left px-4 py-2 rounded font-medium transition ${active === 'user' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}>User Management</button>
        <button onClick={() => onNavigate('order')} className={`text-left px-4 py-2 rounded font-medium transition ${active === 'order' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}>Order Management</button>
        <button onClick={() => onNavigate('product')} className={`text-left px-4 py-2 rounded font-medium transition ${active === 'product' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}>Product Management</button>
      </nav>
      <div className="flex-1" />
      <button onClick={() => onNavigate('logout')} className="mt-8 px-4 py-2 rounded bg-red-50 text-red-600 font-semibold hover:bg-red-100 transition">Logout</button>
    </aside>
  );
}
